import Navigation from "../components/Navigation";

const Home = () => {
    return (
        <section className="home-section">
            <main className="home bg-img-custom w-100">
                <div className="logo-section bg-img-custom"></div>
            </main>
            <Navigation />
        </section>
    );
}

export default Home;
